def formula(var_asset1, var_asset2, correlation):
    # Correlated Portfolio VaR for two assets
    # Derived from portfolio variance: Var_p = w1^2*s1^2 + w2^2*s2^2 + 2*w1*w2*s1*s2*rho
    # where VaR_i = z * wi * sigma_i, so VaR_i^2 terms replace variance contributions
    portfolio_var_squared = (
        var_asset1 ** 2
        + var_asset2 ** 2
        + 2.0 * correlation * var_asset1 * var_asset2
    )
    return np.sqrt(portfolio_var_squared)

